import { createClient } from "@sanity/client";
import { readFileSync } from "fs";
import { resolve } from "path";
const envPath = resolve(process.cwd(), ".env.local");
const envLines = readFileSync(envPath, "utf8").split("\n");
for (const line of envLines) {
  const [key, ...rest] = line.split("=");
  if (key && rest.length) process.env[key.trim()] = rest.join("=").trim();
}
const client = createClient({ projectId: "wa86etuq", dataset: "production", apiVersion: "2024-01-01", useCdn: false, token: process.env.SANITY_API_TOKEN });

let _k = 0;
const k = () => `rw05_${++_k}`;

const h2 = (t) => ({ _type:"block",_key:k(),style:"h2",markDefs:[],children:[{_type:"span",_key:k(),text:t,marks:[]}] });
const h3 = (t) => ({ _type:"block",_key:k(),style:"h3",markDefs:[],children:[{_type:"span",_key:k(),text:t,marks:[]}] });
const p = (t) => ({ _type:"block",_key:k(),style:"normal",markDefs:[],children:[{_type:"span",_key:k(),text:t,marks:[]}] });
const p_b = (segs) => ({ _type:"block",_key:k(),style:"normal",markDefs:[],children:segs.map(s=>({_type:"span",_key:k(),text:s.t,marks:s.b?["strong"]:[]})) });
const stats = (...items) => ({ _type:"statRow",_key:k(),stats:items.map(([v,l])=>({_key:k(),value:v,label:l})) });
const callout = (variant, title, body) => ({ _type:"callout",_key:k(),variant,title,body });
const pq = (text) => ({ _type:"pullquote",_key:k(),text });
const p_link = (before, anchor, href, after) => {
  const lk = k();
  return { _type:"block",_key:k(),style:"normal",markDefs:[{_key:lk,_type:"link",href}],children:[...(before?[{_type:"span",_key:k(),text:before,marks:[]}]:[]),{_type:"span",_key:k(),text:anchor,marks:[lk]},{_type:"span",_key:k(),text:(after||""),marks:[]}] };
};

const body = [
  // === SECTION 1: THE SHORT ANSWER ===
  h2("The Short Answer: India Is One of the World's Biggest Social Media Markets"),
  p("India is not just a large social media market. It is one of the most diverse, multilingual, and engagement-driven social media ecosystems on the planet. With over 500 million active social media users and an average daily usage time of 2.8 hours, Indian consumers spend more time on social platforms than audiences in most Western markets. The opportunity is enormous. But the execution errors that most Indian businesses make are equally enormous."),
  p("The platforms dominating India in 2026 are WhatsApp, YouTube, Instagram, Facebook, and LinkedIn. Each platform has a distinct user behaviour, content format preference, and conversion pathway. A strategy that works on LinkedIn will fall flat on WhatsApp. A tactic that drives sales on Instagram may not translate to YouTube. Understanding the platform-specific landscape is the foundation of any effective social media strategy for Indian businesses."),
  p("Here is the current state of social media reach in India as of 2026:"),
  stats(["530M", "WhatsApp MAU India"], ["462M", "YouTube MAU India"], ["362M", "Instagram MAU India"], ["314M", "Facebook MAU India"], ["120M", "LinkedIn India Users"]),
  p("The numbers are staggering, but they come with important nuance. WhatsApp users are not passively scrolling. They are actively messaging, sharing content, and making purchase decisions in group chats. YouTube users in India skew heavily toward Hindi and regional language content. Instagram has the highest commercial intent among urban Indian consumers aged 18-35. LinkedIn India has grown 40% in three years as the professional class expands. Facebook remains powerful in Tier 2 and Tier 3 cities where it was the first internet experience for many users."),
  p("The 2.8 hours of daily social media usage in India is not evenly distributed across platforms. Most Indian users move between three to four platforms daily, using each for a specific purpose. WhatsApp for communication, YouTube for entertainment and learning, Instagram for discovery and aspiration, and LinkedIn for professional identity. A business that understands these distinct mental modes will create content that fits the moment rather than interrupting it."),
  stats(["2.8 hrs", "Average Daily Social Media Time India"], ["74%", "Indian Users on 3+ Platforms Daily"], ["68%", "Purchases Influenced by Social Media"], ["42%", "B2B Decisions Influenced by LinkedIn"]),

  // === SECTION 2: THE FUNDAMENTAL RULE ===
  h2("The Fundamental Rule All Indian Businesses Break"),
  p("Walk through any Indian business social media account and you will see the same pattern. Posts about their products. Posts about their awards. Posts about their team outing. Posts about their new office. Posts announcing that they are happy to serve you. This is broadcast mode, and it is the primary reason most Indian business social media accounts have low engagement, slow follower growth, and zero commercial return."),
  p("Broadcast mode treats social media as a notice board. The business decides what it wants to say, formats it into a post, and publishes it. There is no consideration for what the audience wants to learn, what problems they are trying to solve, or what conversation they are already having. The result is content that gets ignored not because the audience does not care about the business, but because the content does not give them a reason to care."),
  p("The conversation model flips this completely. Instead of asking 'what do we want to say today?', you ask 'what does our audience need to understand today?'. Instead of announcing your product launch, you explain the problem your product solves and let the audience self-select. Instead of posting your award, you share the lesson that led to the award. The content becomes useful, and useful content gets shared."),
  pq("The brands winning on Indian social media are solving problems in public, not advertising in public"),
  p("This distinction matters especially in the Indian context because Indian consumers are highly sceptical of advertising and highly responsive to genuine expertise. A chartered accountant who posts a weekly 'tax tip for small business owners' will build more business from social media than one who posts monthly reminders that they offer GST filing services. A software company that shares case studies of how they solved a specific supply chain problem will attract more B2B leads than one that posts about their certifications."),
  p("The shift from broadcast to conversation also changes the metrics you track. Broadcast mode measures reach and impressions. Conversation mode measures comments, saves, shares, and DMs. These are the metrics that predict business outcomes. A post with 10,000 impressions and zero comments has low commercial value. A post with 500 impressions and 40 comments from your target audience has high commercial value. Indian businesses that understand this distinction invest their social media budget very differently."),
  p("The most advanced Indian businesses on social media have moved beyond conversation to community. They are not just responding to comments; they are creating contexts where their audience converses with each other. LinkedIn newsletters, WhatsApp groups for customers, YouTube community posts, Instagram broadcast channels. These owned communities are the highest-value social media asset a business can build because the platform algorithm cannot take them away."),

  // === SECTION 3: INSTAGRAM ===
  h2("Instagram: Dos and Donts for Indian Businesses"),
  p("Instagram is India's highest-intent commercial social media platform. With 362 million users predominantly aged 18-35, concentrated in urban and semi-urban areas, it is the primary discovery channel for consumer brands, professional services, D2C products, and any business targeting India's aspirational middle class. But Instagram's algorithm in 2026 rewards very specific behaviours and penalises others. Here is what Indian businesses need to know."),
  h3("Instagram Dos for Indian Businesses"),
  p_b([{t:"Use Reels as your primary content format.",b:true},{t:" Instagram Reels receive 70% more organic reach than static posts on the platform. The algorithm actively promotes Reels to non-followers, making them the most powerful discovery tool available to Indian businesses without paid advertising. A well-produced Reel explaining a common problem your business solves can reach tens of thousands of potential customers who have never heard of you. Budget for at least three to four Reels per week if Instagram is a primary channel.",b:false}]),
  p_b([{t:"Use Hindi and regional language captions alongside English.",b:true},{t:" Research consistently shows that regional language content generates 18% higher engagement rates among Indian Instagram users. This does not mean abandoning English. Bilingual captions, Hindi hashtags alongside English ones, or full regional language posts for region-specific campaigns all outperform English-only content for Indian B2C brands. For businesses serving Maharashtra, Gujarati content; for Tamil Nadu, Tamil captions; for pan-India campaigns, Hindi reaches the widest audience.",b:false}]),
  p_b([{t:"Show the process, not just the result.",b:true},{t:" Behind-the-scenes content consistently outperforms polished advertising content on Indian Instagram. A saree manufacturer filming the weaving process, a restaurant showing how the chef prepares the signature dish, a software company showing their developers whiteboarding a solution. Indian audiences respond to authenticity and craft. The imperfect, real-world content that shows how something is made or how a problem is solved generates more trust and commercial intent than professionally shot product images.",b:false}]),
  p_b([{t:"Use Stories daily for updates, polls, and questions.",b:true},{t:" Instagram Stories have a 24-hour shelf life but they keep your brand in the daily awareness of your followers. Use Stories to share quick updates, ask polls (What colour do you prefer? Which service do you need most?), run question stickers, and share UGC from your customers. Stories are lower effort than feed posts and they train the algorithm to show your content to followers who engage regularly. Businesses that post Stories daily see significantly higher feed post reach among their existing follower base.",b:false}]),
  p_b([{t:"Collaborate with Indian micro-influencers in your niche.",b:true},{t:" Micro-influencers with 10,000 to 100,000 followers typically charge between Rs 5,000 and Rs 25,000 per post in India and deliver engagement rates of 4-8%, compared to mega-influencers who charge Rs 2-10 lakh per post but deliver engagement rates of 0.5-2%. For most Indian businesses, a campaign with five micro-influencers produces better commercial results than a single mega-influencer post. The key is relevance: a micro-influencer whose audience exactly matches your target customer is worth more than a celebrity whose audience is broad.",b:false}]),
  p_b([{t:"Add your WhatsApp Business link in the Instagram bio.",b:true},{t:" Indian buyers almost universally prefer to complete purchases or pre-qualify services over WhatsApp rather than through Instagram DMs or website forms. Adding a wa.me link to your Instagram bio and including a 'WhatsApp us' CTA in your posts and Stories dramatically increases conversion rates. The handoff from Instagram discovery to WhatsApp conversation is the most effective conversion pathway for Indian businesses on this platform.",b:false}]),
  h3("Instagram Donts for Indian Businesses"),
  p_b([{t:"Do not use stock images featuring non-Indian people for Indian B2C brands.",b:true},{t:" This is one of the most common and damaging mistakes made by Indian businesses using social media templates. Indian consumers immediately notice when a brand's visual content does not reflect their own reality. Generic Western stock images communicate inauthenticity. For any brand targeting Indian consumers, investing in original photography or India-specific stock libraries is non-negotiable. Your audience should be able to see themselves in your content.",b:false}]),
  p_b([{t:"Do not post without a clear call to action.",b:true},{t:" Every Instagram post should have a purpose. What do you want the viewer to do? Comment their experience, save the post for later, DM you for pricing, click the link in bio, share with a friend. Without a CTA, even well-produced content generates passive consumption rather than commercial action. The CTA does not need to be sales-oriented every time, but it should direct the audience toward a specific engagement.",b:false}]),
  p_b([{t:"Do not ignore DMs.",b:true},{t:" Indian buyers use Instagram DMs to pre-qualify purchases before committing. They ask about pricing, availability, customisation options, and delivery timelines. A business that responds to DMs within one hour converts significantly more of these enquiries than one that responds within 24 hours. Instagram's algorithm also rewards accounts with high DM response rates by increasing the organic reach of their posts. Treating DMs as a sales channel, not a customer service inconvenience, is fundamental to Instagram success in India.",b:false}]),
  p_b([{t:"Do not rely exclusively on English for regional audiences.",b:true},{t:" If your business serves customers primarily in non-metro markets or in regions with strong language identity (Tamil Nadu, Kerala, West Bengal, Punjab, Gujarat), English-only content creates a psychological distance between your brand and your potential customers. Even basic gestures toward regional language, a greeting in the local language, a product name in regional script, significantly improve connection and conversion in these markets.",b:false}]),
  p_b([{t:"Do not buy followers.",b:true},{t:" Purchased followers on Instagram are a business liability, not an asset. Instagram's algorithm allocates reach based on engagement rate (engagement divided by follower count). An account with 50,000 purchased followers and 200 genuine engagements per post has an engagement rate of 0.4%, which signals low-quality content to the algorithm. Your organic posts then get shown to fewer genuine followers. The mathematics of purchased followers permanently damage organic reach. Build to 10,000 genuine followers rather than inflate to 100,000 fake ones.",b:false}]),
  p_b([{t:"Do not post inconsistently.",b:true},{t:" Instagram's algorithm explicitly rewards consistency. Accounts that post three to five times per week, at predictable intervals, receive preferential distribution compared to accounts that post 15 times one week and twice the next. Create a content calendar, batch-produce content once per week, and schedule posts using a scheduling tool. The algorithm treats your account as a content partner worth promoting when you demonstrate consistent, reliable output.",b:false}]),

  // === SECTION 4: LINKEDIN ===
  h2("LinkedIn: Dos and Donts for Indian B2B Businesses"),
  p("LinkedIn India has grown from a job portal reputation to the primary B2B marketing platform for Indian professionals. With 120 million Indian users as of 2026, including a rapidly growing segment of senior decision-makers, startup founders, and corporate buyers, LinkedIn has become essential for any Indian B2B company, SaaS product, professional service, or consulting firm. The platform rewards specific content behaviours with exceptional organic reach that is increasingly unavailable on other platforms."),
  p_link("Understanding LinkedIn as part of a broader digital marketing strategy is critical for B2B success. The businesses that use LinkedIn most effectively treat it as their primary thought leadership channel, not just a recruitment tool. For a comprehensive view of how this fits into a full digital marketing approach, see our analysis of ", "why strategic digital marketing firms are critical for business success", "/insights/why-strategic-digital-marketing-firms-are-critical-for-business-success", "."),
  h3("LinkedIn Dos for Indian B2B Businesses"),
  p_b([{t:"Publish long-form articles directly on LinkedIn.",b:true},{t:" LinkedIn articles receive three times more reach than posts that include external links, because LinkedIn's algorithm actively demotes content that redirects users off the platform. A 1,000-word article about a challenge your clients face, written from your experience and published natively on LinkedIn, will outperform a link to a blog post on your website. Write the full thought on LinkedIn, then mention your website as a resource at the end.",b:false}]),
  p_b([{t:"Use first-person founder and employee content, not brand page posts.",b:true},{t:" Personal LinkedIn profiles receive 5-10 times more organic reach than company pages. Indian B2B buyers prefer to understand who they will be working with, not just what company they will be engaging. Founder posts that share genuine insights, lessons learned, and opinions attract far more engagement than corporate announcements. Coach your senior team to post consistently on their personal profiles and have the company page share and amplify this content.",b:false}]),
  p_b([{t:"Comment on 10 posts before publishing your own.",b:true},{t:" This is one of the most effective LinkedIn growth tactics available to Indian professionals in 2026. Commenting thoughtfully on posts by target customers, industry peers, and sector influencers before publishing your own content signals to LinkedIn's algorithm that you are an active community participant, not a broadcast publisher. The algorithm rewards active participants with broader distribution of their own posts. Spend 15 minutes commenting every morning before your own posting.",b:false}]),
  p_b([{t:"Use LinkedIn polls strategically.",b:true},{t:" LinkedIn polls generate five times higher engagement than standard text posts because they are frictionless to engage with (one click to vote) and generate curiosity among other users who want to see the results. For Indian B2B businesses, polls work particularly well when they surface genuine industry questions. 'What is your biggest challenge with GST compliance?', 'Which is more important for your IT decisions: cost reduction or security?'. The comments on these polls become your most valuable prospect intelligence.",b:false}]),
  p_b([{t:"Share data with India-specific context.",b:true},{t:" Indian LinkedIn users respond strongly to data-driven posts that contextualise global trends for the Indian market. A global statistic about cybersecurity costs means less to an Indian CTO than the same statistic reframed for Indian SME spending. Adding Indian rupee costs, Indian regulatory context, and Indian market dynamics to data posts dramatically increases engagement and positions your business as a local expert rather than a global generic.",b:false}]),
  p_b([{t:"Post at 7-9 AM or 12-1 PM IST.",b:true},{t:" These are the peak LinkedIn engagement windows for Indian professionals. The morning window captures professionals checking LinkedIn before work or during their commute. The lunchtime window captures the break-time browsing habit. Posts published at 7 AM IST consistently outperform those published at 2 PM or 6 PM for Indian B2B audiences. Schedule your best content for these windows and save lower-priority content for other times.",b:false}]),
  h3("LinkedIn Donts for Indian B2B Businesses"),
  p_b([{t:"Do not send connection requests without a personalised note.",b:true},{t:" The default LinkedIn connection request is one of the most ignored messages in professional communication. A personalised note that references something specific ('I read your post on cloud migration challenges for Indian banks and wanted to connect') converts three to four times better than the generic 'I would like to add you to my professional network.' The note does not need to be long. It needs to be specific.",b:false}]),
  p_b([{t:"Do not post job openings as your primary content.",b:true},{t:" Brands that use their LinkedIn presence primarily to post job openings train their audience to ignore their content. Job posts get low engagement from non-job-seekers, which tanks the account's overall engagement rate and reduces the organic reach of all future posts. Maintain a ratio of at least five value-adding posts (insights, case studies, opinions) for every one job posting.",b:false}]),
  p_b([{t:"Do not use generic stock images.",b:true},{t:" LinkedIn's algorithm and Indian professional audiences both respond poorly to the visual language of generic stock photography. Images of suited professionals pointing at whiteboards, handshakes in glass-walled offices, and laptops on desks communicate nothing and establish no identity. Original images of your team, your work, your clients (with permission), or data visualisations perform significantly better. If you cannot use original images, text-only posts often outperform stock image posts on LinkedIn.",b:false}]),
  p_b([{t:"Do not send immediate sales pitches after connecting.",b:true},{t:" The immediate sales pitch after a LinkedIn connection is the single most complained-about behaviour on the platform among Indian professionals. Sending a pitch within 24 hours of connecting destroys any goodwill the personalised connection note created. Build the relationship first. Comment on their posts. Share useful content. The pitch, when it eventually comes, lands in a context of established credibility rather than cold interruption.",b:false}]),
  p_b([{t:"Do not post more than once per day.",b:true},{t:" LinkedIn's algorithm penalises accounts that post more than once in a 24-hour period by distributing each subsequent post to a smaller audience. Unlike Instagram or Twitter where frequency is rewarded, LinkedIn rewards quality and spacing. One excellent post per day outperforms three average posts. If you have multiple pieces of content ready, schedule them across different days rather than publishing them simultaneously.",b:false}]),

  // === SECTION 5: YOUTUBE ===
  h2("YouTube: Dos and Donts for Indian Businesses"),
  p("YouTube is India's second-largest social platform and its most powerful long-form video channel. With 462 million monthly active users, YouTube in India is not just an entertainment platform. It is the primary self-education tool for Indian consumers and professionals. Businesses that create genuinely educational YouTube content in the right language, with the right format, and at the right frequency build audiences that convert at substantially higher rates than any other social channel."),
  p("The most important strategic insight for Indian businesses on YouTube is that Hindi content receives three times more search volume than equivalent English content for many product and service categories. A tax advisor who creates a Hindi YouTube channel explaining GST filing for small businesses will attract more qualified leads from YouTube than one who creates polished English-language content for a narrower, already-served audience. The Hindi YouTube space remains dramatically underserved relative to demand."),
  h3("YouTube Dos for Indian Businesses"),
  p_b([{t:"Optimise for Hindi and regional language SEO.",b:true},{t:" YouTube is a search engine as much as it is a social platform. Most Indian users search in Hindi or their regional language, particularly for practical topics like how to file GST returns, how to choose a water purifier, or how to implement ERP software. Research the Hindi keywords in your category using YouTube's search suggest feature. Create titles, descriptions, and tags in both Hindi and English to capture both search audiences. Thumbnails with Hindi text overlay consistently outperform English-only thumbnails for Indian searches.",b:false}]),
  p_b([{t:"Add chapters and timestamps to all videos.",b:true},{t:" YouTube chapters, created by adding timestamps to video descriptions, appear as navigable segments on the video progress bar. Indian YouTube users have high intent but also high impatience. Chapters allow viewers to jump directly to the section most relevant to them, which dramatically increases overall watch time and reduces early drop-off. A 20-minute video about choosing accounting software becomes far more useful when a viewer can jump directly to the 'GST compliance considerations' chapter at 12:30.",b:false}]),
  p_b([{t:"Respond to comments within the first two hours of publishing.",b:true},{t:" YouTube's algorithm measures comment engagement velocity (how quickly comments arrive and are responded to) as a signal of content quality. Responding to every comment on a new video within the first two hours dramatically increases the video's early distribution. For Indian business channels, this early engagement window often determines whether a video reaches 500 views or 5,000 views in its first 48 hours. Plan to be available to respond to comments immediately after each new upload.",b:false}]),
  p_b([{t:"Develop a YouTube Shorts strategy alongside long-form content.",b:true},{t:" YouTube Shorts (vertical videos under 60 seconds) have become a major discovery mechanism in India, with Indian users consuming significantly more Shorts than the global average. For businesses, Shorts serve as a top-of-funnel tool to introduce new viewers to the channel, with a CTA directing them to the longer videos for deeper learning. A chartered accountant could post daily 60-second 'tax tip' Shorts that funnel viewers to their 20-minute explainer videos.",b:false}]),
  p_b([{t:"Create videos around specific questions your customers ask.",b:true},{t:" The most effective YouTube content for Indian businesses answers the exact questions that potential customers ask before making a purchase decision. These are not brand videos. They are problem-solving videos. A cybersecurity company does not post 'Our Security Solutions Overview'. They post 'How to Protect Your Business from Ransomware Attacks in India'. The specificity of the question determines both the search discoverability and the commercial relevance of the content.",b:false}]),
  h3("YouTube Donts for Indian Businesses"),
  p_b([{t:"Do not create video intros longer than 15 seconds.",b:true},{t:" YouTube analytics consistently show that Indian viewers drop off in large numbers during long branded intros. The animated logo, the jingle, the 'welcome to our channel' preamble. Indian viewers want to reach the value immediately. Start every video by stating what the viewer will learn in the first 10 seconds, then deliver it. The brand identity should come through in your presentation style and consistent visual language, not a 30-second intro sequence.",b:false}]),
  p_b([{t:"Do not use monotone or reading-from-script delivery.",b:true},{t:" Indian YouTube audiences have been trained by years of high-energy, personality-driven content from Indian YouTubers. Flat, corporate-presentation delivery in a video context signals low production care and causes viewers to disengage within the first minute. This does not mean you need to be artificially enthusiastic. It means you should vary your pace, use concrete examples, tell brief stories, and speak as if you are explaining something to an interested friend rather than presenting to a board.",b:false}]),
  p_b([{t:"Do not neglect your video thumbnails.",b:true},{t:" Thumbnail click-through rate (CTR) is the primary variable determining how broadly YouTube distributes your video in search results and recommendations in India. A video with a 10% CTR will receive dramatically more organic distribution than the same video with a 3% CTR. Effective Indian YouTube thumbnails typically feature a clear, high-contrast face showing an expressive emotion, bold text in a large font that supplements the title, and a visual element that creates curiosity. Testing two or three thumbnail variants is standard practice for serious Indian YouTube channels.",b:false}]),
  p_b([{t:"Do not upload infrequently without communicating a schedule.",b:true},{t:" YouTube's algorithm rewards channels that upload on a predictable schedule. If you publish every Tuesday and Thursday, the algorithm builds expectations around your upload cadence and promotes your new videos to subscribers more aggressively on those days. If you upload randomly, once a month or whenever a video is ready, the algorithm treats you as an unpredictable publisher and reduces subscriber notification reach. Decide on a sustainable schedule (even once per week is fine) and maintain it.",b:false}]),

  // === SECTION 6: WHATSAPP BUSINESS ===
  h2("WhatsApp Business: Dos and Donts for Indian Businesses"),
  p("WhatsApp is India's dominant communication platform and, for many Indian businesses, the highest-converting sales channel available. With 530 million monthly active users in India and penetration across every demographic, income group, and region, WhatsApp is not optional for Indian businesses. It is the default communication expectation of Indian consumers. The businesses that treat WhatsApp as a strategic marketing channel, not just a customer service tool, unlock conversion rates that no other platform can match."),
  callout("info", "WhatsApp: India's Highest-Conversion Marketing Channel", "Indian businesses using WhatsApp Business professionally report conversion rates of 40-70% for warm leads contacted via WhatsApp, compared to 2-5% for email and less than 1% for social media posts. The intimacy and immediacy of WhatsApp creates a sales environment that no other digital channel replicates for Indian buyers."),
  h3("WhatsApp Business Dos for Indian Businesses"),
  p_b([{t:"Build broadcast lists for warm leads and existing customers.",b:true},{t:" WhatsApp broadcast lists allow you to send messages to up to 256 contacts simultaneously, with each recipient receiving the message as an individual conversation rather than a group chat. This preserves the personal quality of WhatsApp communication. Use broadcast lists to share new product launches, seasonal offers, and useful content with customers who have already bought from you or expressed clear interest. Open rates on WhatsApp broadcasts regularly exceed 85% in India, compared to 20-25% for email newsletters.",b:false}]),
  p_b([{t:"Use voice notes for complex updates and explanations.",b:true},{t:" Voice notes are a uniquely Indian WhatsApp behaviour that significantly outperforms text messages for complex or nuanced communication. A consultant explaining a quarterly business review, a doctor explaining a treatment plan, a financial advisor explaining an investment option. Voice notes feel personal, save typing time, and convey tone and expertise in ways that text cannot. For professional services businesses, voice notes on WhatsApp have become a powerful relationship-building tool.",b:false}]),
  p_b([{t:"Set up the WhatsApp Business catalog feature for product businesses.",b:true},{t:" WhatsApp Business's catalog feature allows Indian businesses to create a product gallery accessible directly within WhatsApp. For D2C brands, retail businesses, and manufacturers, this means potential customers can browse your products, see prices, and send enquiries without leaving WhatsApp. Businesses using the catalog feature report a 30-45% reduction in the time from first contact to purchase decision, because the product information is immediately accessible in the conversation.",b:false}]),
  p_b([{t:"Set automated welcome messages and quick replies.",b:true},{t:" WhatsApp Business allows automated welcome messages for new contacts and quick reply shortcuts for your most common responses. A new contact reaching out after seeing your Instagram ad should receive an immediate automated welcome that sets expectations about response time and provides basic information. Quick replies for common questions (pricing, location, service areas, turnaround time) reduce response time and ensure consistent information is delivered every time.",b:false}]),
  h3("WhatsApp Business Donts for Indian Businesses"),
  p_b([{t:"Do not send unsolicited messages.",b:true},{t:" India's Telecom Regulatory Authority of India (TRAI) regulations and WhatsApp's own policies prohibit sending unsolicited commercial messages on WhatsApp. Beyond the legal risk, unsolicited WhatsApp messages generate high block rates that permanently damage your WhatsApp Business account's reputation and can lead to account suspension. Every contact on your WhatsApp broadcast lists and in your WhatsApp campaigns must have explicitly opted in to receive communications from you.",b:false}]),
  p_b([{t:"Do not use WhatsApp for bulk cold prospecting.",b:true},{t:" WhatsApp is a warm-channel tool. It works extraordinarily well for converting contacts who already know your business: website visitors who shared their number, leads generated through Instagram or LinkedIn, referrals from existing customers, attendees of your webinars or events. Using purchased number databases for WhatsApp cold outreach violates TRAI regulations, results in mass blocking, and destroys the sender account. Cold prospecting belongs on LinkedIn or email, not WhatsApp.",b:false}]),
  p_b([{t:"Do not neglect the opt-in process.",b:true},{t:" Any WhatsApp marketing programme requires a clear opt-in mechanism. This can be as simple as a checkbox on your website contact form ('I consent to receive updates via WhatsApp'), a verbal agreement captured in CRM notes for phone enquiries, or a WhatsApp link on your social media that initiates contact from the customer's side. The opt-in creates the legal and ethical foundation for all subsequent WhatsApp communication. Document opt-ins carefully.",b:false}]),
  p_b([{t:"Do not treat WhatsApp as a broadcast-only channel.",b:true},{t:" The biggest mistake businesses make with WhatsApp marketing is treating it like SMS or email: one-way broadcasts with no expectation of response. WhatsApp's commercial power comes from its conversational nature. When a broadcast generates a reply, respond quickly and personally. These one-on-one conversations convert at dramatically higher rates than any broadcast. Train your team to treat every WhatsApp reply as a high-priority sales conversation.",b:false}]),
  p_link("For businesses considering how to integrate WhatsApp into a broader digital marketing strategy, including how it connects to social media advertising and content, see our guide on ", "social media marketing for businesses in Pune", "/insights/social-media-marketing-company-pune-2026", "."),

  // === SECTION 7: CONTENT TYPES ===
  h2("Content Types That Outperform in India"),
  p("Not all content formats perform equally across the Indian social media landscape. Years of data from Indian businesses across industries reveal consistent patterns in which content types generate the strongest engagement, the most shares, and, crucially, the highest commercial conversion rates. Understanding these format preferences is not about chasing trends. It is about engineering content that is structurally likely to succeed in the Indian social media context."),
  p("The following performance data reflects engagement and conversion benchmarks across Indian business accounts with between 5,000 and 500,000 followers, across multiple industries including professional services, consumer products, SaaS, and retail. These are directional averages, not absolute guarantees, but they represent consistent patterns observed across the Indian market."),
  stats(["40% more saves", "Educational Carousel Posts"], ["65% more shares", "Before and After Posts"], ["80% more comments", "Founder Personal Story Posts"], ["55% more DMs", "Price Transparency Posts (B2B)"]),
  p_b([{t:"Educational carousel posts",b:true},{t:" (multi-slide posts on Instagram and LinkedIn) are the highest-save content format across Indian social media. A carousel titled '7 GST Mistakes That Cost Indian Businesses Money' or '5 Signs Your IT Infrastructure Needs an Upgrade' gets saved by users who want to refer back to it. Saves are the highest-quality engagement signal for the algorithm, as they indicate the viewer found the content genuinely useful. Educational carousels generate 40% more saves than equivalent single-image posts.",b:false}]),
  p_b([{t:"Before and after posts",b:true},{t:" are the highest-share format across Indian social media. Whether it is a website redesign, a factory floor reorganisation, a client's revenue chart before and after implementing your service, or a before-and-after product result, the transformation format triggers the human instinct to share surprising changes. Before-and-after posts generate 65% more shares than standard product posts, dramatically extending their organic reach at zero additional cost.",b:false}]),
  p_b([{t:"Founder personal story posts",b:true},{t:" generate the highest comment volumes across Indian LinkedIn and Instagram. Stories of failure, unexpected lessons, controversial opinions, or honest accounts of what building a business actually looks like attract genuine conversation. Indian professional audiences are hungry for authenticity from business leaders. A founder who shares a genuine mistake they made and what they learned from it will receive more engagement than the same founder announcing a company milestone. These posts generate 80% more comments than standard brand content.",b:false}]),
  callout("tip", "Price Transparency: The Indian B2B Content Advantage", "Indian B2B buyers overwhelmingly prefer suppliers who are transparent about pricing, even approximately. Posts that share pricing ranges, package structures, or cost frameworks generate 55% more DMs from qualified prospects than equivalent posts that omit pricing. The common fear that price transparency reduces perceived value is inverted in the Indian B2B market: transparency is interpreted as confidence, not desperation. Be the company in your sector that is honest about what things cost."),
  p_b([{t:"Case study posts with specific numbers",b:true},{t:" are the highest-converting content type for Indian B2B businesses on LinkedIn. Not 'We helped a client improve their operations' but 'How we helped a 45-person manufacturing company in Nashik reduce their monthly IT support costs by Rs 1.2 lakh while improving uptime from 94% to 99.7%'. The specificity signals credibility. The named location (Nashik) signals relevance. The concrete numbers eliminate vague promises. Indian B2B decision-makers share this type of content with their colleagues because it makes a specific, verifiable claim.",b:false}]),
  p_b([{t:"Industry myth-busting posts",b:true},{t:" generate exceptional engagement across all Indian social platforms. Posts that challenge common assumptions in your industry. 'The biggest myth about cloud migration in India', 'What no one tells you about Instagram advertising for Indian businesses', 'Why the common advice about GST planning is wrong for small manufacturers'. The counter-intuitive framing creates curiosity, and curiosity drives clicks, comments, and shares. Use this format to demonstrate expert knowledge that contradicts lazy conventional wisdom.",b:false}]),

  // === SECTION 8: POSTING FREQUENCY AND TIMING ===
  h2("Posting Frequency and Timing by Platform for Indian Businesses"),
  p("Getting your content seen by the right audience at the right time is as important as the content itself. Indian social media users have predictable daily patterns shaped by work schedules, commute habits, and cultural rhythms. The optimal posting times for Indian audiences differ from global averages, particularly the US-centric timing that dominates most social media scheduling guides. Here is the platform-by-platform guide for Indian businesses in 2026."),
  h3("Instagram: Timing and Frequency for Indian Audiences"),
  p("For Indian Instagram audiences, the highest-engagement windows are 7-9 AM (morning commute and breakfast), 12-2 PM (lunch break browsing), and 8-10 PM (evening relaxation). Sunday evenings (7-9 PM IST) consistently produce the highest reach for Indian Instagram accounts because professional audiences are winding down from the weekend and priming for the work week."),
  p_b([{t:"Recommended posting frequency: 4-5 feed posts per week, 7 Stories per day, 3-4 Reels per week.",b:true},{t:" Consistency matters more than volume. A business posting three times per week every week will outperform one posting 15 times one week and twice the next. Use a content calendar and batch-create content once per week to maintain this cadence without daily creative pressure.",b:false}]),
  h3("LinkedIn: Timing and Frequency for Indian Professionals"),
  p("Indian LinkedIn users are most active between 7-9 AM IST (before or during morning commute), 12-1 PM IST (lunch break), and Tuesday through Thursday show the highest engagement volumes. Monday mornings see high activity but lower engagement as users are entering work mode. Friday afternoons see sharp engagement drops as Indian professionals wind down for the weekend."),
  p_b([{t:"Recommended posting frequency: 1 post per day maximum, 4-5 times per week.",b:true},{t:" Quality over volume is LinkedIn's primary algorithm principle. A single well-researched, genuinely insightful post per day will dramatically outperform two or three shorter posts. Reserve your best content for Tuesday through Thursday mornings and use Monday and Friday for lower-stakes content.",b:false}]),
  h3("YouTube: Upload Schedule for Indian Channels"),
  p("YouTube engagement for Indian audiences peaks on Saturday and Sunday mornings (9 AM to 12 PM IST) for entertainment and lifestyle content, and on Tuesday and Wednesday evenings (7-9 PM IST) for professional and educational content. This distinction matters: if your YouTube content is educational, your professional audience is more likely to be in learning mode midweek evenings than weekend mornings."),
  p_b([{t:"Recommended upload frequency: 1-2 videos per week for business channels.",b:true},{t:" YouTube's algorithm rewards consistent uploading more than volume. A channel uploading one video every Tuesday will outperform a channel uploading five videos one week and none the next. For YouTube Shorts, daily publishing is viable and recommended because Shorts have a different distribution mechanism than long-form videos.",b:false}]),
  h3("WhatsApp: Messaging Windows for Indian Audiences"),
  p("WhatsApp messages sent to Indian audiences perform best when received between 9-11 AM (after morning routines are complete) and 4-6 PM (the pre-evening engagement window). Avoid sending business WhatsApp messages after 9 PM IST. Even though WhatsApp is a personal channel, late-night business messages are considered intrusive and generate higher opt-out rates among Indian users."),
  p_b([{t:"Recommended broadcast frequency: 2-3 broadcasts per week maximum.",b:true},{t:" WhatsApp broadcast frequency should be conservative. Indian consumers who feel they are receiving too many marketing messages on WhatsApp will block your number, which permanently removes them from your audience. Under-communicate rather than over-communicate, and ensure every broadcast provides clear, immediate value.",b:false}]),

  // === SECTION 9: COMMON MISTAKES ===
  h2("Common Social Media Mistakes by Indian Businesses (With Fixes)"),
  p("Beyond the platform-specific dos and donts, there are cross-platform mistakes that consistently undermine Indian businesses' social media investment. These mistakes are not born of laziness. They come from misunderstanding how social media algorithms work, what Indian audiences respond to, and how social media connects to business outcomes. Here are the most common, with specific fixes for each."),
  p_link("The businesses that avoid these mistakes most consistently tend to be those working with specialised social media partners rather than managing everything internally. For context on how to choose the right social media support for an Indian business, see our analysis of ", "AI social media services versus traditional agencies", "/insights/ai-social-media-services-vs-traditional-agencies-2026", " in 2026."),
  h3("Mistake 1: Treating All Platforms as the Same"),
  p("The most common strategic mistake is creating one piece of content and posting it identically across Instagram, LinkedIn, Facebook, and WhatsApp. Each platform has distinct content norms, audience expectations, and algorithm behaviours. A LinkedIn post format (long text, professional tone, industry insight) will receive minimal engagement on Instagram. An Instagram Reel will look out of place shared to a LinkedIn feed. Repurposing content across platforms is efficient; cross-posting without adaptation is damaging."),
  p_b([{t:"The fix:",b:true},{t:" Create a 'content adaptation' workflow. Start with a core idea or piece of information, then adapt the format, tone, length, and visual language for each platform. A client case study becomes a detailed LinkedIn article, a before-and-after carousel on Instagram, a 10-minute YouTube video, and a concise WhatsApp voice note summary for existing clients.",b:false}]),
  h3("Mistake 2: Measuring Vanity Metrics Instead of Business Metrics"),
  p("Most Indian businesses track followers, likes, and impressions. These metrics are visible, easy to understand, and emotionally satisfying when they grow. They are also largely disconnected from business outcomes. A Instagram account with 50,000 followers and no DMs, no website traffic, and no attributed sales is a vanity trophy, not a business asset."),
  p_b([{t:"The fix:",b:true},{t:" Define the business metric each social channel is meant to drive before creating any content. For Instagram, it might be WhatsApp enquiries. For LinkedIn, it might be content downloads leading to sales conversations. For YouTube, it might be website visits from video descriptions. Track these downstream metrics monthly. If a platform is consuming budget and time without generating these business outcomes after 90 days, reconsider the investment or the strategy.",b:false}]),
  h3("Mistake 3: Ignoring the Role of Social Proof"),
  p("Indian buyers are extremely social-proof-driven. Before making a significant purchase, most Indian consumers and B2B buyers seek reassurance from others who have made the same decision. Testimonials, case studies, client logos, user-generated content, and reviews are not nice-to-haves in the Indian market. They are fundamental purchase decision inputs. Businesses that do not actively generate and share social proof on their social channels are leaving significant conversion on the table."),
  p_b([{t:"The fix:",b:true},{t:" Build a systematic social proof generation programme. After every successful project or purchase, ask for a Google review, a LinkedIn recommendation, or a WhatsApp testimonial that can be shared (with permission) as a screenshot. Create a monthly 'client story' post on Instagram and LinkedIn. Feature testimonials in Instagram Story highlights. The social proof content that feels most authentic, informal phone screenshots of client praise rather than polished corporate testimonials, consistently converts better in the Indian market.",b:false}]),
  h3("Mistake 4: No Budget for Content Production"),
  p("Many Indian businesses budget for social media advertising but allocate nothing for content production. The result is low-quality content that performs poorly organically, which then requires more advertising budget to get any reach. This is an expensive cycle. High-quality organic content reduces the advertising spend needed to reach your target audience, because the algorithm distributes good content more broadly."),
  p_b([{t:"The fix:",b:true},{t:" Allocate a minimum of 30% of your total social media budget to content production (photography, video, graphic design, copywriting) and a maximum of 70% to paid distribution. For most Indian SMEs, this means a monthly content production budget of Rs 15,000-50,000 and a paid distribution budget of Rs 30,000-100,000, depending on the scale of ambition. Businesses in competitive categories who invest in content quality as the foundation of their paid strategy consistently outperform those who boost low-quality content.",b:false}]),
  h3("Mistake 5: Not Linking Social Media to a Sales System"),
  p("Social media generates awareness, interest, and enquiries. It does not automatically generate sales. The gap between a social media enquiry and a closed sale requires a functional sales follow-up system. Many Indian businesses generate healthy social media enquiries that then fall through the cracks because there is no CRM, no follow-up protocol, and no lead nurturing sequence. The social media channel then gets blamed for poor results when the problem is actually in the conversion process."),
  p_b([{t:"The fix:",b:true},{t:" Connect every social media channel to a defined follow-up process. Instagram DMs and WhatsApp enquiries should be logged in a CRM or at minimum a shared spreadsheet within 24 hours. Every enquiry should receive a follow-up within 48 hours if they have not converted. LinkedIn connections who engage with multiple posts should be identified weekly and added to a personalised outreach cadence. Social media generates the leads; the sales system converts them.",b:false}]),
  p_link("For businesses building out the full digital marketing and sales funnel that social media feeds into, our guide on ", "strengthening your content strategy with customer input", "/insights/strengthen-your-content-strategy-with-customer-input", " provides a framework for aligning content creation with sales outcomes."),

  // === SECTION 10: PAID SOCIAL MEDIA ===
  h2("Paid Social Media in India: When to Boost and When to Build"),
  p("Organic social media reach is declining on every major platform in India. Instagram's organic reach for business accounts has dropped from approximately 8% of followers in 2020 to under 3% in 2026. LinkedIn organic reach has compressed as the platform monetises its growing Indian user base. YouTube remains the strongest organic reach platform for Indian businesses, but even there, paid promotion accelerates channel growth for new accounts."),
  p("The role of paid social media for Indian businesses in 2026 is not to replace organic strategy but to amplify content that is already performing organically. Many Indian businesses make the mistake of spending advertising budget on content that has demonstrated zero organic engagement. Boosting a post that got 5 likes and 0 comments will not generate better commercial results at scale. The algorithm interprets low organic engagement as low quality, and paid promotion cannot override that signal completely."),
  p_b([{t:"The rule for paid social amplification:",b:true},{t:" Only boost content that has already demonstrated above-average organic engagement. A post that received twice your normal engagement rate in the first four hours of organic posting is a strong candidate for paid amplification. A post that received below-average engagement organically is telling you the content does not resonate with the audience. Spending money to show more people content that does not resonate produces expensive negative results.",b:false}]),
  callout("tip", "The 70-30 Rule for Indian Social Media Budgets", "Effective Indian businesses allocate roughly 70% of their social media budget to content creation and organic community building, and 30% to paid amplification of their best-performing organic content. This ratio is the inverse of what most agencies recommend, because most agencies earn commission on ad spend. Businesses that invest in content quality first and pay to amplify proven content consistently outperform those that boost mediocre content heavily."),
  p("For Indian B2B businesses on LinkedIn, the most cost-effective paid strategy in 2026 is not boosting posts but using LinkedIn Lead Gen Forms targeted to specific job titles, company sizes, and industries. A LinkedIn Lead Gen Form campaign targeted to Operations Directors and IT Heads at manufacturing companies with 100-500 employees in Maharashtra, offering a free operational audit, will generate better-qualified leads than a broad awareness campaign at a fraction of the cost."),
  p("For Indian B2C businesses on Instagram and Facebook, the most cost-effective paid strategy remains retargeting: showing ads specifically to people who have already visited your website, watched your videos, or engaged with your organic posts. Retargeting audiences have dramatically higher conversion rates than cold audiences because they already have some familiarity with your brand. For Indian e-commerce businesses, retargeting campaigns targeting cart abandoners and past purchasers routinely deliver return on ad spend of 8-15x, compared to 2-4x for cold audience campaigns."),
  h3("Facebook and Instagram Ads: India-Specific Targeting Considerations"),
  p("India's geographic and demographic diversity makes audience targeting one of the most important skills in paid social for Indian businesses. A campaign targeting 'India, 25-45, urban' is not targeted. It is a very expensive broad campaign. Effective Indian paid social targets by city tier (Metro, Tier 1, Tier 2), by language preference (Hindi, Tamil, Telugu, Marathi), by device type (Android users in India have very different purchasing behaviour from iPhone users), and by income proxy indicators."),
  p("Meta's income targeting for India has improved significantly in 2026 with better integration of financial behaviour signals. For B2C businesses targeting premium segments, layering income signals, device type (iPhone users), and specific area code-level geographic targeting can achieve cost per qualified lead that is 60-70% lower than broad demographic targeting. For B2B businesses using Facebook and Instagram, retargeting LinkedIn profile visitors (via pixel) and creating lookalike audiences from existing client email lists are the most effective approaches."),
  stats(["3x lower CPA", "Retargeting vs Cold Audiences India"], ["8-15x ROAS", "Cart Abandonment Retargeting India"], ["60-70% lower CPL", "Granular Geo Targeting vs Broad India"], ["5x more leads", "LinkedIn Lead Gen Forms vs Link Ads"]),

  // === SECTION 11: SOCIAL MEDIA ROI MEASUREMENT ===
  h2("Measuring Social Media ROI for Indian Businesses"),
  p("Return on investment from social media is one of the most debated and misunderstood metrics in Indian digital marketing. The difficulty is real: social media rarely drives direct, last-click purchases for most Indian businesses. Its impact is typically in the earlier stages of the buyer journey, building awareness, establishing credibility, and warming leads before they convert through another channel (a phone call, a WhatsApp message, a Google search). This multi-touch attribution problem leads many Indian businesses to either over-credit or under-credit social media's contribution."),
  p("The solution is to measure social media impact at multiple levels, not just at the final conversion point. A framework that works for most Indian businesses involves three measurement tiers: content performance metrics (engagement rate, saves, shares, comment quality), channel traffic metrics (website sessions from social, WhatsApp clicks from social bios, DM volumes), and business outcome metrics (leads attributed to social, revenue from socially-warmed clients)."),
  p_b([{t:"Content performance metrics",b:true},{t:" tell you whether your content strategy is working. Target an average engagement rate of 3-5% on Instagram, 1-3% on LinkedIn, and a save rate of 0.5-1% on both platforms. Below these benchmarks, the content is not resonating with the audience. Above these benchmarks, the content is outperforming and should be studied for patterns to replicate.",b:false}]),
  p_b([{t:"Channel traffic metrics",b:true},{t:" tell you whether social media is driving the right people toward commercial action. Track monthly: unique website sessions from social media (Google Analytics), WhatsApp link clicks from Instagram bio (use a UTM-tagged wa.me link), DM volumes by platform, and email list signups attributed to social media. These metrics bridge the gap between content performance and business outcomes.",b:false}]),
  p_b([{t:"Business outcome metrics",b:true},{t:" require deliberate tracking. Ask every new client or prospect how they heard about you and record the answer. For online enquiries, use UTM parameters in all social media links to track which platform and which specific post drove each website enquiry. Review your CRM monthly to identify deals where social media was mentioned in the discovery process. Over 6-12 months, this data will reveal the true commercial contribution of each social platform.",b:false}]),
  callout("warning", "The 90-Day Minimum for Social Media Assessment", "Most Indian businesses abandon their social media strategy after 30-60 days because results are not immediately visible. Social media ROI for most businesses requires 90-180 days of consistent execution before meaningful business outcomes appear. The first 90 days build the audience. The second 90 days build the trust. Commercial outcomes typically appear in the third and fourth quarter of a sustained strategy. Businesses that evaluate and change strategy every 4-6 weeks are permanently in the audience-building phase and never reach the trust or conversion phase."),
  p("The most important social media ROI insight for Indian businesses is that the cost comparison is not between social media and zero. It is between social media and the alternatives: print advertising, trade shows, cold calling, and traditional PR. When measured against these alternatives for the quality and volume of leads generated, well-executed social media consistently delivers a lower cost per qualified lead for most Indian businesses in 2026. The challenge is the patience required to let the strategy compound."),

  // === SECTION 12: BUILDING A SOCIAL MEDIA SYSTEM ===
  h2("Building a Social Media System That Indian Businesses Can Actually Sustain"),
  p("The reason most Indian businesses fail at social media is not lack of knowledge about what to do. It is lack of a system that makes consistent execution possible without consuming disproportionate time from founders and senior staff. Social media strategies that require daily creative decisions, individual post writing, and real-time responses are unsustainable for most Indian SMEs. The strategy needs to be systematised to be sustained."),
  p("A sustainable social media system for an Indian business has four components: a content calendar that maps topics to dates three to four weeks in advance; a content production day each week where multiple pieces of content are created in one session; a scheduling tool that queues posts for optimal times without manual publishing; and a daily 15-30 minute engagement block where all DMs, comments, and responses are handled."),
  p_b([{t:"The content calendar",b:true},{t:" does not need to be complex. A shared Google Sheet with columns for date, platform, content type, topic, and status is sufficient. Plan content themes by month (for example, November is Diwali-adjacent, March is financial year-end for Indian businesses) and map recurring content types to specific days (Monday is tip day on LinkedIn, Wednesday is case study day on Instagram). The calendar transforms daily creative pressure into a weekly planning exercise.",b:false}]),
  p_b([{t:"The content production day",b:true},{t:" is the operational heart of a sustainable social media strategy. Set aside four to six hours once per week, ideally Monday or Tuesday morning, to produce all content for the following week or two weeks. This batching approach dramatically increases content quality because you are in creation mode, not response mode. Film all video content in one session. Write all captions together. Design all graphics in one sitting. The cognitive load of context-switching between creation and other work is eliminated.",b:false}]),
  p_b([{t:"Scheduling tools",b:true},{t:" available to Indian businesses include Meta Business Suite (free for Facebook and Instagram), LinkedIn's native post scheduler (free), Buffer (paid, supports all major platforms), and Hootsuite (enterprise). For most Indian SMEs, Meta Business Suite and LinkedIn's native scheduler are sufficient and cost nothing. Schedule posts 3-7 days in advance. This removes the daily pressure of 'what do I post today' and ensures consistent publishing even during busy business periods.",b:false}]),
  pq("The businesses that win at social media in India are not the most creative. They are the most consistent. Consistency is a system problem, not a talent problem."),
  p("The daily engagement block is the most neglected part of a social media system for Indian businesses. Posting content without engaging with responses is like opening a shop and not serving customers who walk in. Allocate a fixed 20-30 minutes each morning and evening to respond to comments, reply to DMs, engage with followers' content, and participate in relevant conversations. This engagement time is where relationships that drive commercial outcomes are actually built. It cannot be delegated entirely, particularly for smaller businesses where the founder's authentic voice is a key differentiator."),
  p("For Indian businesses that genuinely cannot manage social media execution internally, the decision framework is straightforward. If social media is a primary sales channel for your business (true for most B2C and many B2B companies), investing in external support is justified. If social media is a secondary or complementary channel, a part-time internal resource with a clear content calendar may be sufficient. The worst outcome is half-hearted internal execution where social media receives time only when nothing else is urgent, which results in neither the cost savings of full internal management nor the quality of professional support."),

  // === SECTION 13: SOURCES ===
  h2("Sources and Data"),
  p("The statistics and benchmarks in this guide are drawn from the following sources, verified as of early 2026:"),
  p_b([{t:"1. DataReportal Digital 2026: India Report",b:true},{t:" - Platform MAU figures, daily usage time, and demographic breakdown for Indian social media users. The most comprehensive annual dataset for Indian digital behaviour.",b:false}]),
  p_b([{t:"2. Meta Business Insights: India Market Report 2025-26",b:true},{t:" - Instagram and Facebook engagement benchmarks for Indian business accounts, Reels reach data, and regional language content performance data.",b:false}]),
  p_b([{t:"3. LinkedIn Marketing Solutions: India B2B Trends Report 2026",b:true},{t:" - Indian LinkedIn user engagement patterns, content performance benchmarks, and B2B buyer behaviour data specific to Indian professionals.",b:false}]),
  p_b([{t:"4. YouTube India Creator Academy and Official Benchmarks 2025",b:true},{t:" - Hindi versus English content search volume data, thumbnail CTR benchmarks for Indian content, and upload frequency recommendations.",b:false}]),
  p_b([{t:"5. Telecom Regulatory Authority of India (TRAI): Digital Communications Guidelines 2025",b:true},{t:" - Official guidelines on commercial messaging compliance including WhatsApp opt-in requirements and unsolicited communications regulations.",b:false}]),
  p_b([{t:"6. Internet and Mobile Association of India (IAMAI): India Internet Report 2025",b:true},{t:" - Social commerce data, WhatsApp conversion rate benchmarks, and regional language content consumption patterns across Indian digital platforms.",b:false}]),
];

